    unet_sd["up_blocks.11.1.linear_geglu1.bias"] = ckpt["model.diffusion_model.output_blocks.11.1.transformer_blocks.0.ff.net.0.proj.bias"]
    unet_sd["up_blocks.11.1.linear_geglu2.weight"] = ckpt["model.diffusion_model.output_blocks.11.1.transformer_blocks.0.ff.net.2.weight"]
    unet_sd["up_blocks.11.1.linear_geglu2.bias"] = ckpt["model.diffusion_model.output_blocks.11.1.transformer_blocks.0.ff.net.2.bias"]
    unet_sd["up_blocks.11.1.layernorm1.weight"] = ckpt["model.diffusion_model.output_blocks.11.1.transformer_blocks.0.norm1.weight"]
    unet_sd["up_blocks.11.1.layernorm1.bias"] = ckpt["model.diffusion_model.output_blocks.11.1.transformer_blocks.0.norm1.bias"]
    unet_sd["up_blocks.11.1.layernorm2.weight"] = ckpt["model.diffusion_model.output_blocks.11.1.transformer_blocks.0.norm2.weight"]
    unet_sd["up_blocks.11.1.layernorm2.bias"] = ckpt["model.diffusion_model.output_blocks.11.1.transformer_blocks.0.norm2.bias"]
